    createTile,
    createBlockedTile,
    createBlockedMovableTile,
} from "./tile-helpers.js";
import { createBoard } from "./board.js";
import { setupEventListeners } from "./input-handler.js";
import {
    hasMatches,
    hasMatchesForSwap,
    findMatches,
    checkTFormation,
    checkLFormation,
    checkBlockFormation,
} from "./match-detector.js";
import { processMatches } from "./merge-processor.js";
import { animateSwap, animateRevert, dropGems, animateMerges, animateUnblocking } from "./animator.js";
import {
    renderBoard,
    renderGoals,
    renderBoardUpgrades,
    renderPowerUpRewards,
    updateGoalDisplay,
    updateMovesDisplay,
    renderHintHighlight,
} from "./renderer.js";
import { findBestSwap } from "./hint-system.js";
import {
    checkLevelComplete,
