        col1,
        row2,
        col2,
        direction1,
        direction2,
        score,
        matches,
        matchTiles,
    };
}

/**
 * Count how many adjacent swaps on the given board would produce a match.
 * Used as a "board richness" proxy — more options = better board state.
 * @param {object} boardProxy - Object with board, boardWidth, boardHeight (and game methods)
 * @returns {number} Capped at 30
 */
function countBoardRichness(boardProxy) {
    let count = 0;
    for (let row = 0; row < boardProxy.boardHeight; row++) {
        for (let col = 0; col < boardProxy.boardWidth; col++) {
            if (col + 1 < boardProxy.boardWidth && hasMatchesForSwap(boardProxy, row, col, row, col + 1)) count++;
            if (row + 1 < boardProxy.boardHeight && hasMatchesForSwap(boardProxy, row + 1, col, row, col)) count++;
