     1→#!/usr/bin/env node
     2→// Headless level simulator
     3→// Usage: node scripts/simulate.js [options]
     4→//
     5→// Options:
     6→//   --level <n>        Level index (1-based, default: 1)
     7→//   --runs <n>         Number of plays (default: 20)
     8→//   --strategy <name>  "mcts" | "hint" | "random" (default: mcts)
     9→//   --mcts-iters <n>   MCTS iterations (default: 500)
    10→//   --mcts-depth <n>   MCTS rollout depth (default: 4)
    11→//   --mcts-time <ms>   MCTS time limit ms (default: 2000)
    12→//   --config <key>     Level config set: "new" | "test" (default: new)
