    94→export function createCursedTile(value, movesRemaining) {
    95→    return {
    96→        type: TILE_TYPE.CURSED,
    97→        value: value,
    98→        cursedMovesRemaining: movesRemaining,
    99→        createdThisTurn: true, // Skip decrement on the turn this tile was created
   100→        specialType: null,
