   211→}
   212→
   213→export function isTileRandomPowerupTile(tile) {
   214→    return tile && tile.type === TILE_TYPE.NORMAL && tile.specialType === "random_powerup";
   215→}
   216→
   217→export function isTileTeleportTile(tile) {
