   241→// Convert internal value (1, 2, 3...) to display value (powers of 2)
   242→export function getDisplayValue(internalValue) {
   243→    // Powers of 2: 2^1=2, 2^2=4, 2^3=8, 2^4=16, etc.
   244→    return Math.pow(2, internalValue);
   245→}
   246→
   247→// Calculate responsive font size based on display value length
   248→export function getFontSize(displayValue) {
   249→    const length = displayValue.toString().length;
   250→    return 50 - Math.max(0, length - 2) * 7;
   251→}
   252→
   253→export function getUniqueTileValues(game) {
   254→    const allValues = [];
   255→    for (let r = 0; r < game.boardHeight; r++) {
   256→        for (let c = 0; c < game.boardWidth; c++) {
   257→            const tile = game.board[r][c];
   258→            if (tile && tile.type === "normal") {
   259→                const val = getTileValue(tile);
   260→                if (!allValues.includes(val)) {
   261→                    allValues.push(val);
   262→                }
   263→            }
   264→        }
   265→    }
   266→    return allValues;
   267→}
   268→
   269→/**
   270→ * Find the best value for a joker tile to become, based on what creates valid matches.
   271→ * Pure logic: temporarily mutates game.board but restores it before returning.
   272→ */
   273→export function findBestJokerValue(game, jokerRow, jokerCol, requireSwapConnection = false) {
   274→    const originalTile = game.board[jokerRow][jokerCol];
   275→
   276→    if (!isJoker(originalTile)) {
   277→        return null;
   278→    }
   279→
   280→    const allValues = getUniqueTileValues(game);
   281→    allValues.sort((a, b) => b - a);
   282→
   283→    for (const testValue of allValues) {
   284→        game.board[jokerRow][jokerCol] = createTile(testValue);
   285→
   286→        const matches = game.findMatches();
   287→
   288→        const validMatch = matches.find((match) => {
   289→            const includesJoker = match.tiles.some((tile) => tile.row === jokerRow && tile.col === jokerCol);
   290→            if (!includesJoker) return false;
   291→
   292→            if (requireSwapConnection && game.lastSwapPosition) {
   293→                const includesSourceTile = match.tiles.some(
   294→                    (tile) => tile.row === game.lastSwapPosition.row && tile.col === game.lastSwapPosition.col,
   295→                );
   296→                if (!includesSourceTile) return false;
   297→            }
   298→
   299→            const hasOtherJokers = match.tiles.some((tile) => {
   300→                if (tile.row === jokerRow && tile.col === jokerCol) return false;
   301→                return isJoker(game.board[tile.row][tile.col]);
   302→            });
   303→
   304→            return !hasOtherJokers;
   305→        });
   306→
   307→        if (validMatch) {
   308→            game.board[jokerRow][jokerCol] = originalTile;
   309→            return testValue;
   310→        }
   311→    }
   312→
   313→    game.board[jokerRow][jokerCol] = originalTile;
   314→    return null;
   315→}
