     1→#!/usr/bin/env node
     2→// Headless level simulator
     3→// Usage: node scripts/simulate.js [options]
     4→//
     5→// Options:
     6→//   --level <n>        Level index (1-based, default: 1)
     7→//   --runs <n>         Number of plays (default: 20)
     8→//   --strategy <name>  "mcts" | "hint" | "random" (default: mcts)
     9→//   --mcts-iters <n>   MCTS iterations (default: 500)
    10→//   --mcts-depth <n>   MCTS rollout depth (default: 4)
    11→//   --mcts-time <ms>   MCTS time limit ms (default: 2000)
    12→//   --config <key>     Level config set: "new" | "test" (default: new)
    13→//   --verbose          Print per-run details
    14→//   --help             Show this help
    15→
    16→import { parseArgs } from "node:util";
    17→import { findBestSwapMCTS } from "../src/mcts.js";
    18→import { findBestSwap, findAllValidSwaps } from "../src/hint-system.js";
    19→import { simulateMove } from "../src/simulation.js";
    20→import { createBoard } from "../src/board.js";
    21→import { findMatches, checkTFormation, checkLFormation, checkBlockFormation } from "../src/match-detector.js";
    22→import { isBlocked, isBlockedWithLife, isBlockedWithMergeCount, isRectangularBlocked } from "../src/tile-helpers.js";
    23→import { DEFAULT_LEVEL, LEVEL_CONFIGS, DEFAULT_TILE_VALUES } from "../src/config.js";
    24→
    25→// ---------------------------------------------------------------------------
    26→// CLI argument parsing
    27→// ---------------------------------------------------------------------------
    28→
    29→const { values: args } = parseArgs({
    30→    options: {
    31→        level:       { type: "string",  short: "l", default: "1" },
    32→        runs:        { type: "string",  short: "r", default: "20" },
    33→        strategy:    { type: "string",  short: "s", default: "mcts" },
    34→        "mcts-iters":{ type: "string",  default: "500" },
    35→        "mcts-depth":{ type: "string",  default: "4" },
    36→        "mcts-time": { type: "string",  default: "2000" },
    37→        config:      { type: "string",  short: "c", default: "new" },
    38→        verbose:     { type: "boolean", short: "v", default: false },
    39→        help:        { type: "boolean", short: "h", default: false },
    40→    },
    41→    strict: false,
    42→});
    43→
    44→if (args.help) {
    45→    console.log(`Usage: node scripts/simulate.js [options]
    46→
    47→Options:
    48→  --level <n>        Level index (1-based, default: 1)
    49→  --runs <n>         Number of plays (default: 20)
    50→  --strategy <name>  mcts | hint | random (default: mcts)
    51→  --mcts-iters <n>   MCTS iterations per move (default: 500)
    52→  --mcts-depth <n>   MCTS rollout depth (default: 4)
    53→  --mcts-time <ms>   MCTS time limit ms (default: 2000)
    54→  --config <key>     Level config set: new | test (default: new)
    55→  --verbose          Print per-run details
    56→  --help             Show this help`);
    57→    process.exit(0);
    58→}
    59→
    60→const levelIdx  = parseInt(args.level, 10) - 1;
    61→const runs      = parseInt(args.runs, 10);
    62→const strategy  = args.strategy;
    63→const mctsIters = parseInt(args["mcts-iters"], 10);
    64→const mctsDepth = parseInt(args["mcts-depth"], 10);
    65→const mctsTime  = parseInt(args["mcts-time"], 10);
    66→const configKey = args.config;
    67→const verbose   = args.verbose;
    68→
    69→// ---------------------------------------------------------------------------
    70→// Level config resolution
    71→// ---------------------------------------------------------------------------
    72→
    73→const levelConfigSet = LEVEL_CONFIGS.find((c) => c.key === configKey);
    74→if (!levelConfigSet) {
    75→    console.error(`Unknown config key "${configKey}". Available: ${LEVEL_CONFIGS.map((c) => c.key).join(", ")}`);
    76→    process.exit(1);
    77→}
    78→
    79→const levels = levelConfigSet.levels;
    80→if (levelIdx < 0 || levelIdx >= levels.length) {
    81→    console.error(`Level ${levelIdx + 1} not found. Config "${configKey}" has ${levels.length} level(s).`);
    82→    process.exit(1);
    83→}
    84→
    85→const levelConfig = levels[levelIdx];
    86→
    87→// ---------------------------------------------------------------------------
    88→// Game context factory
    89→// ---------------------------------------------------------------------------
    90→
    91→/**
    92→ * Build a minimal game-like object from a level config.
    93→ * Mirrors what game.js does in loadLevel() — no DOM, no storage.
    94→ */
    95→function createGameContext(levelConfig) {
    96→    const tileValues = levelConfig.spawnableTiles || DEFAULT_TILE_VALUES;
    97→
    98→    const game = {
    99→        board: [],
   100→        boardWidth:  levelConfig.boardWidth  || 8,
   101→        boardHeight: levelConfig.boardHeight || 8,
   102→        tileValues,
   103→        spawnableTileValues: tileValues,
   104→        levelConfig,
   105→        blockedTiles: levelConfig.blockedTiles || [],
   106→        specialTileConfig: levelConfig.specialTileConfig || {
   107→            line_4: "freeswap_horizontal",
   108→            block_4: "freeswap_horizontal",
   109→            line_5: "joker",
   110→            t_formation: "freeswap",
   111→            l_formation: "freeswap",
   112→        },
   113→        allowNonMatchingSwaps: levelConfig.allowNonMatchingSwaps || false,
   114→        levelGoals: levelConfig.goals.map((g) => ({ ...g })),
   115→        maxMoves: levelConfig.maxMoves,
   116→        movesUsed: 0,
   117→        score: 0,
   118→        cursedTileCreatedCount: {},
   119→
   120→        // Methods required by board.js and hint-system.js
   121→        checkTFormation(row, col, value) { return checkTFormation(this, row, col, value); },
   122→        checkLFormation(row, col, value)  { return checkLFormation(this, row, col, value); },
   123→        checkBlockFormation(row, col, value) { return checkBlockFormation(this, row, col, value); },
   124→        findMatches() { return findMatches(this); },
   125→    };
   126→
   127→    createBoard(game);
   128→    return game;
   129→}
