   131→// ---------------------------------------------------------------------------
   132→// Board inspection helpers
   133→// ---------------------------------------------------------------------------
   134→
   135→/** Count blocked tiles on the board (all variants). */
   136→function countBlockedTiles(board) {
   137→    const seen = new Set(); // avoid double-counting shared rectangular tile objects
   138→    let count = 0;
   139→    for (const row of board) {
   140→        for (const tile of row) {
   141→            if (!tile) continue;
   142→            if (isBlocked(tile) || isBlockedWithLife(tile) || isBlockedWithMergeCount(tile)) {
   143→                const key = tile.rectId || `${tile.row}_${tile.col}_${Math.random()}`; // unique key
   144→                if (isRectangularBlocked(tile)) {
   145→                    if (!seen.has(tile.rectId)) {
   146→                        seen.add(tile.rectId);
   147→                        count++;
   148→                    }
   149→                } else {
   150→                    count++;
   151→                }
   152→            }
   153→        }
   154→    }
   155→    return count;
   156→}
   157→
   158→/** Count tiles of a specific value on the board. */
   159→function countTileValue(board, tileValue) {
   160→    let count = 0;
   161→    for (const row of board) {
   162→        for (const tile of row) {
   163→            if (tile && tile.value === tileValue) count++;
   164→        }
   165→    }
   166→    return count;
   167→}
