   169→// ---------------------------------------------------------------------------
   170→// Goal checking
   171→// ---------------------------------------------------------------------------
   172→
   173→/**
   174→ * Check if all level goals are met given current state.
   175→ * - "created": cumulative progress tracked in goalTotals
   176→ * - "blocked":  initialBlockedCount - currentBlockedCount >= target
   177→ * - "current":  live board tile count for tileValue >= target
   178→ * - "score":    not simulated (treated as always met)
   179→ */
   180→function checkGoalsMet(levelConfig, goalTotals, board, initialBlockedCount) {
   181→    for (const goal of levelConfig.goals) {
   182→        if (goal.goalType === "created") {
   183→            const achieved = goalTotals[goal.tileValue] || 0;
   184→            if (achieved < goal.target) return false;
   185→        } else if (goal.goalType === "blocked") {
   186→            const currentBlocked = countBlockedTiles(board);
   187→            const cleared = initialBlockedCount - currentBlocked;
   188→            // target is set dynamically in the real game to initialBlockedCount
   189→            const target = goal.target || initialBlockedCount;
   190→            if (cleared < target) return false;
   191→        } else if (goal.goalType === "current") {
   192→            const onBoard = countTileValue(board, goal.tileValue);
   193→            if (onBoard < goal.target) return false;
   194→        }
   195→        // "score" — not simulated, treated as always met
   196→    }
   197→    return true;
   198→}
   199→
   200→// ---------------------------------------------------------------------------
   201→// Strategy: random swap (among swaps that produce a match)
   202→// ---------------------------------------------------------------------------
   203→
   204→function randomSwap(game) {
   205→    const swaps = findAllValidSwaps(game);
   206→    if (swaps.length === 0) return null;
   207→
   208→    // Filter to swaps that actually produce a match (mirrors what simulateMove checks)
   209→    const validSwaps = swaps.filter((s) => {
   210→        const r = simulateMove(game, s);
   211→        return r.valid && r.scoreDelta > 0;
   212→    });
   213→
   214→    if (validSwaps.length === 0) {
   215→        // No matching swaps exist — fall back to any swap (allowNonMatchingSwaps boards)
   216→        return swaps[Math.floor(Math.random() * swaps.length)];
   217→    }
   218→    return validSwaps[Math.floor(Math.random() * validSwaps.length)];
   219→}
   220→
   221→// ---------------------------------------------------------------------------
   222→// Single run simulation
   223→// ---------------------------------------------------------------------------
   224→
   225→/**
   226→ * Simulate one full level play.
   227→ * @returns {{ won: boolean, movesUsed: number, goalTotals: object }}
   228→ */
   229→function simulateRun(levelConfig, strategyFn) {
   230→    const game = createGameContext(levelConfig);
   231→    const goalTotals = {}; // accumulated "created" goal progress
   232→    const initialBlockedCount = countBlockedTiles(game.board);
   233→
   234→    // Apply any pre-existing goal.created values (some levels start with progress)
   235→    for (const goal of levelConfig.goals) {
   236→        if (goal.goalType === "created" && goal.created) {
   237→            goalTotals[goal.tileValue] = goal.created;
   238→        }
   239→    }
   240→
   241→    while (game.movesUsed < game.maxMoves) {
   242→        const swap = strategyFn(game);
   243→        if (!swap) break; // no valid moves
   244→
   245→        const result = simulateMove(game, swap);
   246→        if (!result.valid) {
   247→            if (game.allowNonMatchingSwaps) {
   248→                // Non-matching swap allowed — counts as a move
   249→                game.board = result.newBoard;
   250→                game.movesUsed++;
   251→            } else {
   252→                // Strategy returned a swap that produces no match.
   253→                // This shouldn't happen with a well-behaved strategy, but
   254→                // rather than infinite loop, treat as no valid moves.
   255→                break;
   256→            }
   257→            continue;
   258→        }
   259→
   260→        // Accumulate "created" goal progress
   261→        for (const [tileValue, count] of Object.entries(result.goalProgress)) {
   262→            goalTotals[tileValue] = (goalTotals[tileValue] || 0) + count;
   263→        }
   264→
   265→        // Update game state for next move
   266→        game.board = result.newBoard;
   267→        game.movesUsed++;
   268→
   269→        if (checkGoalsMet(levelConfig, goalTotals, game.board, initialBlockedCount)) {
   270→            return { won: true, movesUsed: game.movesUsed, goalTotals };
   271→        }
   272→    }
   273→
   274→    return { won: false, movesUsed: game.movesUsed, goalTotals };
   275→}
   276→
   277→// ---------------------------------------------------------------------------
   278→// Strategy picker
   279→// ---------------------------------------------------------------------------
   280→
   281→function buildStrategyFn(strategy, mctsConfig) {
   282→    switch (strategy) {
   283→        case "mcts":
   284→            return (game) => findBestSwapMCTS(game, mctsConfig);
   285→        case "hint":
   286→            return (game) => findBestSwap(game);
   287→        case "random":
   288→            return (game) => randomSwap(game);
   289→        default:
   290→            console.error(`Unknown strategy "${strategy}". Use: mcts | hint | random`);
   291→            process.exit(1);
   292→    }
   293→}
   294→
   295→// ---------------------------------------------------------------------------
   296→// Main
   297→// ---------------------------------------------------------------------------
   298→
   299→const mctsConfig = {
   300→    iterations: mctsIters,
   301→    rolloutDepth: mctsDepth,
   302→    timeLimit: mctsTime,
   303→    silent: true,
   304→};
   305→
   306→const strategyFn = buildStrategyFn(strategy, mctsConfig);
   307→
   308→console.log(`\nLevel ${levelIdx + 1}: "${levelConfig.title}"`);
   309→console.log(`Config: ${configKey}  Strategy: ${strategy}  Runs: ${runs}`);
   310→if (strategy === "mcts") {
