   312→}
   313→console.log(`Goals: ${levelConfig.goals.map((g) => `${g.goalType}:${g.tileValue || ""}×${g.target}`).join(", ")}`);
   314→console.log(`Moves: ${levelConfig.maxMoves}  Board: ${levelConfig.boardWidth || 8}×${levelConfig.boardHeight || 8}`);
   315→console.log("─".repeat(50));
   316→
   317→let wins = 0;
   318→let totalMoves = 0;
   319→const startTime = Date.now();
