    if (verbose) {
        const status = result.won ? "WIN " : "LOSS";
        const runElapsed = ((Date.now() - runStart) / 1000).toFixed(1);
        const goalStr = levelConfig.goals.map((g) => {
            if (g.goalType === "created") {
                const achieved = result.goalTotals[g.tileValue] || 0;
                return `${g.tileValue}:${achieved}/${g.target}`;
            } else if (g.goalType === "current") {
                const onBoard = countTileValue(result.finalBoard, g.tileValue);
                return `${g.tileValue}(cur):${onBoard}/${g.target}`;
            } else if (g.goalType === "blocked") {
                const cleared = result.initialBlockedCount - countBlockedTiles(result.finalBoard);
                return `blocked:${cleared}/${result.initialBlockedCount}`;
            }
            return g.goalType;
        }).join("  ");
        process.stdout.write("\r" + " ".repeat(60) + "\r");
        console.log(`  Run ${String(i + 1).padStart(3)}: ${status}  moves=${result.movesUsed}  ${goalStr}  ${runElapsed}s`);
    }
}

