// Hint system for finding and scoring the best possible swap

import { isBlocked, isBlockedWithLife, isBlockedMovable, isBlockedWithMergeCount } from "./tile-helpers.js";
import { hasMatchesForSwap, findMatches } from "./match-detector.js";
import { simulateMove } from "./simulation.js";

/**
 * Main entry point: finds the best swap on the board
 * @param {Match3Game} game - The game instance
 * @returns {{row1: number, col1: number, row2: number, col2: number, score: number} | null}
 */
export function findBestSwap(game) {
    const validSwaps = findAllValidSwaps(game);

    if (validSwaps.length === 0) {
        return null;
    }

    const evaluatedSwaps = [];

    // Save original board reference and flags (don't copy - keep the original intact)
    const originalBoard = game.board;
    const originalIsUserSwap = game.isUserSwap;
    const originalLastSwapPosition = game.lastSwapPosition;

    // Create a working copy for hint evaluation
    // This copy is what we'll modify during evaluation
    const createWorkingCopy = () => originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));

    for (const swap of validSwaps) {
        // Set up a fresh working copy for each evaluation
        game.board = createWorkingCopy();

        const result = evaluateSwap(game, swap.row1, swap.col1, swap.row2, swap.col2);

        if (result !== null) {
            evaluatedSwaps.push(result);
        }
    }

    // Restore original board reference (not a copy - the actual original)
    game.board = originalBoard;
    game.isUserSwap = originalIsUserSwap;
    game.lastSwapPosition = originalLastSwapPosition;

    if (evaluatedSwaps.length === 0) {
        return null;
    }

    // Sort by score descending, with tiebreaker for top-left position
    evaluatedSwaps.sort((a, b) => {
        if (b.score !== a.score) {
            return b.score - a.score;
        }
        // Tiebreaker: prefer top-left positions
        const posA = a.row1 + a.col1;
        const posB = b.row1 + b.col1;
        return posA - posB;
    });

    const bestDirect = evaluatedSwaps[0];

    // Check if a non-matching setup swap leads to a better subsequent match
    const setupSwap = findBestNonMatchingSetup(game, originalBoard);
    if (setupSwap && setupSwap.score > bestDirect.score) {
        return setupSwap;
    }

    return bestDirect;
}

/**
 * Find all valid adjacent swap pairs on the board
 * @param {Match3Game} game - The game instance
 * @returns {Array<{row1: number, col1: number, row2: number, col2: number}>}
 */
export function findAllValidSwaps(game) {
    const validSwaps = [];

    for (let row = 0; row < game.boardHeight; row++) {
        for (let col = 0; col < game.boardWidth; col++) {
            // Check right neighbor
            if (col < game.boardWidth - 1) {
                if (isValidSwapPair(game, row, col, row, col + 1)) {
                    validSwaps.push({
                        row1: row,
                        col1: col,
                        row2: row,
                        col2: col + 1,
                    });
                }
            }

            // Check down neighbor
            if (row < game.boardHeight - 1) {
                if (isValidSwapPair(game, row, col, row + 1, col)) {
                    validSwaps.push({
                        row1: row,
                        col1: col,
                        row2: row + 1,
                        col2: col,
                    });
                }
            }
        }
    }

    return validSwaps;
}

/**
 * Check if two positions can be swapped
 * @param {Match3Game} game - The game instance
 * @param {number} row1 - First tile row
 * @param {number} col1 - First tile column
 * @param {number} row2 - Second tile row
 * @param {number} col2 - Second tile column
 * @returns {boolean}
 */
function isValidSwapPair(game, row1, col1, row2, col2) {
    const tile1 = game.board[row1]?.[col1];
    const tile2 = game.board[row2]?.[col2];

    // Check if tiles exist
    if (!tile1 || !tile2) {
        return false;
    }

    // Check if either tile is blocked
    if (isBlocked(tile1) || isBlockedWithLife(tile1)) {
        return false;
    }

    if (isBlocked(tile2) || isBlockedWithLife(tile2)) {
        return false;
    }

    return true;
}

/**
 * Find the best non-matching "setup" swap: a swap with no immediate match that
 * enables a high-scoring matching swap on the next move.
 * Score is discounted by 0.7 vs direct matches to prefer immediate payoff.
 * @param {Match3Game} game - The game instance
 * @param {Array} originalBoard - The unmodified board 2D array
 * @returns {{row1,col1,row2,col2,score}|null}
 */
function findBestNonMatchingSetup(game, originalBoard) {
    // Skip if level explicitly disables non-matching swaps
    if (game.allowNonMatchingSwaps === false) return null;

    const allSwaps = findAllValidSwaps(game);
    let bestScore = -Infinity;
    let bestSwap = null;

    for (const swap of allSwaps) {
        // Only consider swaps that do NOT produce an immediate match
        if (hasMatchesForSwap(game, swap.row1, swap.col1, swap.row2, swap.col2)) continue;

        // Build a proxy game with the swap applied (no cascade — just position swap)
        const clonedBoard = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
        const temp = clonedBoard[swap.row1][swap.col1];
        clonedBoard[swap.row1][swap.col1] = clonedBoard[swap.row2][swap.col2];
        clonedBoard[swap.row2][swap.col2] = temp;

        const proxyGame = { ...game, board: clonedBoard };

        // Evaluate the best direct matching swap on the resulting board
        // Use evaluateBestDirectScore (internal helper) to avoid infinite recursion
        const followUpScore = evaluateBestDirectScore(proxyGame);
        if (followUpScore === null) continue;

        const discountedScore = followUpScore * 0.7;
        if (discountedScore > bestScore) {
            bestScore = discountedScore;
            bestSwap = { ...swap, score: discountedScore };
        }
    }

    return bestScore > -Infinity ? bestSwap : null;
}

/**
 * Internal helper: return the score of the best direct matching swap on the given game state.
 * Does NOT call findBestNonMatchingSetup (no recursion).
 * @param {object} game - Proxy game object
 * @returns {number|null} Score of best swap, or null if none
 */
function evaluateBestDirectScore(game) {
    const validSwaps = findAllValidSwaps(game);
    const originalBoard = game.board;
    let best = null;

    for (const swap of validSwaps) {
        game.board = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
        const result = evaluateSwap(game, swap.row1, swap.col1, swap.row2, swap.col2);
        if (result !== null && (best === null || result.score > best)) {
            best = result.score;
        }
    }

    game.board = originalBoard;
    return best;
}

/**
 * Evaluate a swap and compute its score
 * @param {Match3Game} game - The game instance
 * @param {number} row1 - First tile row
 * @param {number} col1 - First tile column
 * @param {number} row2 - Second tile row
 * @param {number} col2 - Second tile column
 * @returns {{row1: number, col1: number, row2: number, col2: number, score: number, matches: Array} | null}
 */
function evaluateSwap(game, row1, col1, row2, col2) {
    // Temporarily swap tiles
    const temp = game.board[row1][col1];
    game.board[row1][col1] = game.board[row2][col2];
    game.board[row2][col2] = temp;

    // Set flag for joker activation
    game.isUserSwap = true;
    game.lastSwapPosition = {
        row: row2,
        col: col2,
        movedFrom: { row: row1, col: col1 },
    };

    // Check if this swap creates matches
    const hasMatches = hasMatchesForSwap(game, row1, col1, row2, col2);

    if (!hasMatches) {
        // Swap back
        game.board[row2][col2] = game.board[row1][col1];
        game.board[row1][col1] = temp;
        return null;
    }

    // Get detailed match information
    const matches = findMatches(game);

    // Swap back
    game.board[row2][col2] = game.board[row1][col1];
    game.board[row1][col1] = temp;

    // Run headless simulation to get cascade count and resulting board for richer scoring
    const simResult = simulateMove(game, { row1, col1, row2, col2 });

    // Calculate score
    const score = calculateSwapScore(game, matches, simResult);

    // Determine swap direction for nudge animation
    let direction1, direction2;
    if (col2 > col1) {
        direction1 = "right";
        direction2 = "left";
    } else if (col2 < col1) {
        direction1 = "left";
        direction2 = "right";
    } else if (row2 > row1) {
        direction1 = "down";
        direction2 = "up";
    } else {
        direction1 = "up";
        direction2 = "down";
    }

    // Separate matches by which swap tile they involve
    const matchesForTile1 = matches.filter((match) =>
        match.tiles.some((tile) => tile.row === row1 && tile.col === col1),
    );
    const matchesForTile2 = matches.filter((match) =>
        match.tiles.some((tile) => tile.row === row2 && tile.col === col2),
    );

    // Calculate score for each group to find the best one
    const score1 = matchesForTile1.length > 0 ? calculateSwapScore(game, matchesForTile1, simResult) : 0;
    const score2 = matchesForTile2.length > 0 ? calculateSwapScore(game, matchesForTile2, simResult) : 0;

    // Use matches from the higher-scoring tile only
    const bestMatches = score1 >= score2 ? matchesForTile1 : matchesForTile2;

    // Collect tiles from the best matches only
    // Translate post-swap positions back to pre-swap positions for display
    const matchTiles = [];
    for (const match of bestMatches) {
        for (const tile of match.tiles) {
            let displayRow = tile.row;
            let displayCol = tile.col;

            // If this tile is at a swap position, translate it back
            if (tile.row === row1 && tile.col === col1) {
                // This tile is at position 1 after swap, so it was at position 2 before
                displayRow = row2;
                displayCol = col2;
            } else if (tile.row === row2 && tile.col === col2) {
                // This tile is at position 2 after swap, so it was at position 1 before
                displayRow = row1;
                displayCol = col1;
            }

            matchTiles.push({ row: displayRow, col: displayCol });
        }
    }

    return {
        row1,
        col1,
        row2,
        col2,
        direction1,
        direction2,
        score,
        matches,
        matchTiles,
    };
}

/**
 * Count how many adjacent swaps on the given board would produce a match.
 * Used as a "board richness" proxy — more options = better board state.
 * @param {object} boardProxy - Object with board, boardWidth, boardHeight (and game methods)
 * @returns {number} Capped at 30
 */
function countBoardRichness(boardProxy) {
    let count = 0;
    for (let row = 0; row < boardProxy.boardHeight; row++) {
        for (let col = 0; col < boardProxy.boardWidth; col++) {
            if (col + 1 < boardProxy.boardWidth && hasMatchesForSwap(boardProxy, row, col, row, col + 1)) count++;
            if (row + 1 < boardProxy.boardHeight && hasMatchesForSwap(boardProxy, row + 1, col, row, col)) count++;
        }
    }
    return Math.min(count, 30);
}

/**
 * Calculate composite score for a swap based on matches
 * @param {Match3Game} game - The game instance
 * @param {Array} matches - Array of match objects
 * @param {object|null} simResult - Optional result from simulateMove for richer scoring
 * @returns {number}
 */
function calculateSwapScore(game, matches, simResult = null) {
    let score = 0;

    let maxFormationScore = 0;
    let totalTilesCleared = 0;
    let maxValue = 0;
    let goalProgress = 0;
    let blockedCleared = 0;
    let hasSpecialTile = false;

    for (const match of matches) {
        // Formation type priority
        let formationScore = 0;
        const direction = match.direction;

        if (direction === "line_5_horizontal" || direction === "line_5_vertical") {
            formationScore = 1000;
        } else if (direction === "T-formation" || direction === "L-formation") {
            formationScore = 800;
        } else if (direction === "line_4_horizontal" || direction === "line_4_vertical") {
            formationScore = 600;
        } else if (direction === "block_4_formation") {
            formationScore = 500;
        } else {
            formationScore = 300; // 3-line matches
        }

        maxFormationScore = Math.max(maxFormationScore, formationScore);

        // Count tiles cleared
        totalTilesCleared += match.tiles.length;

        // Track max value
        maxValue = Math.max(maxValue, match.value);

        // Check for special tile creation based on formation type
        if (direction === "T-formation" || direction === "L-formation" || direction.includes("line_5")) {
            hasSpecialTile = true;
        }
    }

    // Calculate goal progress — score merges that create goal tiles, weighted by urgency
    if (game.levelGoals && game.levelGoals.length > 0) {
        for (const match of matches) {
            const isTL = match.direction === "T-formation" || match.direction === "L-formation";
            const is5Line = match.direction === "line_5_horizontal" || match.direction === "line_5_vertical";
            // The merge result value: +2 for T/L/5-line, +1 for everything else
            const mergedValue = match.value + (isTL || is5Line ? 2 : 1);

            for (const goal of game.levelGoals) {
                if (goal.goalType === "created" && goal.tileValue === mergedValue) {
                    // How much of the goal is still needed? 1.0 = nothing done yet, ~0 = nearly done
                    const remaining = Math.max(0, goal.target - (goal.created || 0));
                    if (remaining <= 0) continue; // goal already met, no bonus
                    // Urgency multiplier: scales from 1× (far from done) to 3× (last tile needed)
                    const urgency = 1 + 2 * (1 - Math.min(remaining, goal.target) / goal.target);
                    // T/L/5-line produce 1 merged tile; 4-line/block produce 2; 3-line produces 1
                    const mergedCount = isTL || is5Line ? 1 :
                        (match.direction === "line_4_horizontal" || match.direction === "line_4_vertical" ||
                         match.direction === "block_4_formation") ? 2 : 1;
                    goalProgress += Math.min(mergedCount, remaining) * urgency * 300;
                } else if (goal.goalType === "current" && goal.tileValue === mergedValue) {
                    const remaining = Math.max(0, goal.target - (goal.current || 0));
                    if (remaining <= 0) continue;
                    const urgency = 1 + 2 * (1 - Math.min(remaining, goal.target) / goal.target);
                    goalProgress += urgency * 300;
                }
            }
        }
    }

    // Calculate blocked tiles that would be cleared (deduplicated by position)
    const adjacentBlockedSeen = new Set();
    for (const match of matches) {
        for (const tile of match.tiles) {
            const adjacentPositions = [
                [tile.row - 1, tile.col],
                [tile.row + 1, tile.col],
                [tile.row, tile.col - 1],
                [tile.row, tile.col + 1],
            ];

            for (const [adjRow, adjCol] of adjacentPositions) {
                if (adjRow >= 0 && adjRow < game.boardHeight && adjCol >= 0 && adjCol < game.boardWidth) {
                    const adjTile = game.board[adjRow]?.[adjCol];
                    if (
                        adjTile &&
                        (isBlocked(adjTile) ||
                            isBlockedWithLife(adjTile) ||
                            isBlockedMovable(adjTile) ||
                            isBlockedWithMergeCount(adjTile))
                    ) {
                        const key = adjTile.rectId || `${adjRow}_${adjCol}`;
                        if (!adjacentBlockedSeen.has(key)) {
                            adjacentBlockedSeen.add(key);
                            blockedCleared += 1;
                        }
                    }
                }
            }
        }
    }

    // NOTE: If there are blocked tiles on the board, there is always a corresponding
    // blocked-tiles goal. So we don't need to check whether that goal is currently "open".

    // Calculate position bonus (matches closer to bottom trigger more cascades)
    let totalRow = 0;
    let tileCount = 0;
    for (const match of matches) {
        for (const tile of match.tiles) {
            totalRow += tile.row;
            tileCount++;
        }
    }
    // Average row position (0 = top, boardHeight-1 = bottom)
    // Bonus scales from 0 to ~150 based on position
    const avgRow = tileCount > 0 ? totalRow / tileCount : 0;
    const positionBonus = Math.round((avgRow / (game.boardHeight - 1)) * 150);

    // Compute composite score
    score += maxFormationScore;
    score += totalTilesCleared * 50;
    score += goalProgress; // already weighted internally above

    // Blocked tile scoring
    // If a swap clears blocked tiles, heavily prefer it.
    if (blockedCleared > 0) {
        // Massive bonus that dominates most other factors, scaled by cleared blocked tiles.
        score += 10000 + blockedCleared * 500;
    }

    score += hasSpecialTile ? 200 : 0;
    score += maxValue * 5;
    score += positionBonus;

    // Cascade and board richness bonuses (from headless simulation)
    if (simResult) {
        // Cascades: each chain reaction is a strong signal of board quality
        score += simResult.cascades * 80;

        // Board richness: count available matches on resulting board
        // More options = better board state for future moves
        const boardProxy = { ...game, board: simResult.newBoard };
        score += countBoardRichness(boardProxy) * 20;
    }

    return score;
}

/**
 * Get the tiles that would be matched if a swap is performed
 * Used by swap preview during drag
 * @param {Match3Game} game - The game instance
 * @param {number} row1 - First tile row
 * @param {number} col1 - First tile column
 * @param {number} row2 - Second tile row
 * @param {number} col2 - Second tile column
 * @returns {Array<{row: number, col: number}>} Array of tile positions in PRE-SWAP coordinates
 */
export function getMatchTilesForSwap(game, row1, col1, row2, col2) {
    // Save original board reference and flags (don't modify the original)
    const originalBoard = game.board;
    const originalIsUserSwap = game.isUserSwap;
    const originalLastSwapPosition = game.lastSwapPosition;

    // Create a working copy for the evaluation
    game.board = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));

    // Swap tiles on the working copy
    const temp = game.board[row1][col1];
    game.board[row1][col1] = game.board[row2][col2];
    game.board[row2][col2] = temp;

    // Set flag for joker activation
    game.isUserSwap = true;
    game.lastSwapPosition = {
        row: row2,
        col: col2,
        movedFrom: { row: row1, col: col1 },
    };

    // Check if this swap creates matches
    const hasMatches = hasMatchesForSwap(game, row1, col1, row2, col2);

    let matchTiles = [];
    if (hasMatches) {
        // Get detailed match information
        const matches = findMatches(game);

        // Only include matches that involve the actively dragged tile
        // The dragged tile starts at (row1, col1) and after swap is at (row2, col2)
        const relevantMatches = matches.filter((match) =>
            match.tiles.some((tile) => tile.row === row2 && tile.col === col2),
        );

        // Collect tiles from relevant matches only
        // Translate post-swap positions back to pre-swap positions for display
        for (const match of relevantMatches) {
            for (const tile of match.tiles) {
                let displayRow = tile.row;
                let displayCol = tile.col;

                // If this tile is at a swap position, translate it back
                if (tile.row === row1 && tile.col === col1) {
                    // This tile is at position 1 after swap, so it was at position 2 before
                    displayRow = row2;
                    displayCol = col2;
                } else if (tile.row === row2 && tile.col === col2) {
                    // This tile is at position 2 after swap, so it was at position 1 before
                    displayRow = row1;
                    displayCol = col1;
                }

                matchTiles.push({ row: displayRow, col: displayCol });
            }
        }
    }

    // Restore original board reference (not a copy)
    game.board = originalBoard;
    game.isUserSwap = originalIsUserSwap;
    game.lastSwapPosition = originalLastSwapPosition;

    return matchTiles;
}

