/**
 * Find the best non-matching "setup" swap: a swap with no immediate match that
 * enables a high-scoring matching swap on the next move.
 * Score is discounted by 0.7 vs direct matches to prefer immediate payoff.
 * @param {Match3Game} game - The game instance
 * @param {Array} originalBoard - The unmodified board 2D array
 * @returns {{row1,col1,row2,col2,score}|null}
 */
function findBestNonMatchingSetup(game, originalBoard) {
    // Skip if level explicitly disables non-matching swaps
    if (game.allowNonMatchingSwaps === false) return null;

    const allSwaps = findAllValidSwaps(game);
    let bestScore = -Infinity;
    let bestSwap = null;

    for (const swap of allSwaps) {
        // Only consider swaps that do NOT produce an immediate match
        if (hasMatchesForSwap(game, swap.row1, swap.col1, swap.row2, swap.col2)) continue;

        // Build a proxy game with the swap applied (no cascade — just position swap)
        const clonedBoard = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
        const temp = clonedBoard[swap.row1][swap.col1];
        clonedBoard[swap.row1][swap.col1] = clonedBoard[swap.row2][swap.col2];
        clonedBoard[swap.row2][swap.col2] = temp;

        const proxyGame = { ...game, board: clonedBoard };

        // Evaluate the best direct matching swap on the resulting board
        // Use evaluateBestDirectScore (internal helper) to avoid infinite recursion
        const followUpScore = evaluateBestDirectScore(proxyGame);
        if (followUpScore === null) continue;

        const discountedScore = followUpScore * 0.7;
        if (discountedScore > bestScore) {
            bestScore = discountedScore;
            bestSwap = { ...swap, score: discountedScore };
        }
    }

    return bestScore > -Infinity ? bestSwap : null;
}

/**
 * Internal helper: return the score of the best direct matching swap on the given game state.
 * Does NOT call findBestNonMatchingSetup (no recursion).
 * @param {object} game - Proxy game object
 * @returns {number|null} Score of best swap, or null if none
 */
function evaluateBestDirectScore(game) {
    const validSwaps = findAllValidSwaps(game);
    const originalBoard = game.board;
    let best = null;

    for (const swap of validSwaps) {
        game.board = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
        const result = evaluateSwap(game, swap.row1, swap.col1, swap.row2, swap.col2);
        if (result !== null && (best === null || result.score > best)) {
            best = result.score;
        }
    }

    game.board = originalBoard;
    return best;
}

